DropCurrentSessionContext.query:
query DropCurrentSessionContext($channelLogin: String, $channelID: ID) {
  currentUser {
    dropCurrentSession(channelLogin: $channelLogin, channelID: $channelID) {
      dropID
      currentMinutesWatched
      requiredMinutesWatched
      status
      game {
        id
        displayName
        __typename
      }
      __typename
    }
    __typename
  }
}
